<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/auth.php';require_once dirname(__DIR__,2).'/includes/conexion.php';exigirAutenticacion();
if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf($_POST['csrf_token']??null)){$_SESSION['perfil_mensaje']='Solicitud inválida.';header('Location: '.atenea_url('src/estudiantes/perfil.php'));exit;}
$cfg=require dirname(__DIR__,2).'/config/google.php';$autoload=dirname(__DIR__,2).'/vendor/autoload.php';if($cfg['client_id']===''||!is_file($autoload)){$_SESSION['perfil_mensaje']='Google aún no está configurado.';header('Location: '.atenea_url('src/estudiantes/perfil.php'));exit;}
